// tools.js
export function getWeather({ city }) {
  return `The temperature in ${city} is 22 degrees celsius and sunny.`;
}

export function calculator({ expression }) {
  // demo only -- never eval untrusted input in production
  return String(Function(`"use strict"; return (${expression})`)());
}

export const TOOL_FNS = { get_weather: getWeather, calculator };

export const TOOLS = [
  { type: "function", function: {
      name: "get_weather",
      description: "Get the current weather for a city.",
      parameters: { type: "object", properties: {
          city: { type: "string", description: "City name, e.g. Paris" } },
        required: ["city"] } } },
  { type: "function", function: {
      name: "calculator",
      description: "Evaluate an arithmetic expression, e.g. '22 * 3 * 0.15'.",
      parameters: { type: "object", properties: {
          expression: { type: "string", description: "Expression to evaluate" } },
        required: ["expression"] } } },
];

// detect.js
import OpenAI from "openai";
import { TOOLS } from "./tools.js";

const client = new OpenAI();
const messages = [{ role: "user", content: "What is the weather in Paris?" }];

const resp = await client.chat.completions.create({
  model: "gpt-5-mini", messages, tools: TOOLS });
const msg = resp.choices[0].message;

if (msg.tool_calls) { // the model wants a tool, not a final answer
  for (const tc of msg.tool_calls) {
    console.log(tc.function.name, tc.function.arguments);
    // -> get_weather {"city":"Paris"}
  }
} else {
  console.log(msg.content);
}

// roundtrip.js
import OpenAI from "openai";
import { TOOLS, TOOL_FNS } from "./tools.js";

const client = new OpenAI();
const messages = [{ role: "user", content:
  "What is the weather in Paris? Then compute 22 * 3 * 0.15." }];

while (true) {
  const resp = await client.chat.completions.create({
    model: "gpt-5-mini", messages, tools: TOOLS });
  const msg = resp.choices[0].message;
  if (!msg.tool_calls) {
    console.log(msg.content); // final answer
    break;
  }
  messages.push(msg); // keep the assistant turn with its tool calls
  for (const tc of msg.tool_calls) {
    const args = JSON.parse(tc.function.arguments);
    const result = TOOL_FNS[tc.function.name](args);
    messages.push({ role: "tool", tool_call_id: tc.id, content: result });
  }
}

