import Anthropic from "@anthropic-ai/sdk";

const client = new Anthropic();
const tools = [{ name: "get_weather",
  description: "Get the current weather for a city.",
  input_schema: { type: "object", properties: {
      city: { type: "string" } }, required: ["city"] } }];

const messages = [{ role: "user", content: "What is the weather in Paris?" }];
const resp = await client.messages.create({ model: "claude-sonnet-4-6",
  max_tokens: 1024, tools, messages });

if (resp.stop_reason === "tool_use") {
  const tu = resp.content.find((b) => b.type === "tool_use");
  const result = `22 degrees celsius and sunny in ${tu.input.city}`;
  messages.push({ role: "assistant", content: resp.content });
  messages.push({ role: "user", content: [{
    type: "tool_result", tool_use_id: tu.id, content: result }] });
  const final = await client.messages.create({ model: "claude-sonnet-4-6",
    max_tokens: 1024, tools, messages });
  console.log(final.content[0].text);
}

