// registry.js
export const REGISTRY = new Map([
  ["get_weather", {
    fn: ({ city }) => `The temperature in ${city} is 22 degrees celsius.`,
    description: "Get the current weather for a city.",
    schema: { type: "object", properties: {
        city: { type: "string" } }, required: ["city"] },
  }],
  ["calculator", {
    // demo only -- never eval untrusted input in production
    fn: ({ expression }) =>
      String(Function(`"use strict"; return (${expression})`)()),
    description: "Evaluate an arithmetic expression like '22 * 3 * 0.15'.",
    schema: { type: "object", properties: {
        expression: { type: "string" } }, required: ["expression"] },
  }],
]);

export const TOOLS = [...REGISTRY].map(([name, spec]) => ({
  type: "function",
  function: { name, description: spec.description, parameters: spec.schema },
}));

// agent.js
import OpenAI from "openai";
import { REGISTRY, TOOLS } from "./registry.js";

const client = new OpenAI();

export async function runAgent(task, maxIterations = 8) {
  const messages = [
    { role: "system",
      content: "Use the tools to answer. Work one step at a time." },
    { role: "user", content: task },
  ];
  for (let i = 0; i < maxIterations; i++) {
    const resp = await client.chat.completions.create({
      model: "gpt-5-mini", messages, tools: TOOLS });
    const msg = resp.choices[0].message;
    if (!msg.tool_calls) return msg.content; // the model is done
    messages.push(msg); // history: assistant turn with tool calls
    for (const tc of msg.tool_calls) {
      const args = JSON.parse(tc.function.arguments);
      console.log(`[iter ${i}] ${tc.function.name}(${tc.function.arguments})`);
      let result;
      try {
        result = REGISTRY.get(tc.function.name).fn(args);
      } catch (e) {
        result = `Error: ${e.message}`; // let the model see it and recover
      }
      messages.push({ role: "tool", tool_call_id: tc.id, content: result });
    }
  }
  return "Stopped: hit maxIterations guard.";
}

