// state.js
import { Annotation, messagesStateReducer } from "@langchain/langgraph";

export const State = Annotation.Root({
  // messagesStateReducer appends new messages instead of overwriting
  messages: Annotation({
    reducer: messagesStateReducer,
    default: () => [],
  }),
});

// graph.js
import { tool } from "@langchain/core/tools";
import { z } from "zod";
import { ChatOpenAI } from "@langchain/openai";
import { StateGraph, START } from "@langchain/langgraph";
import { ToolNode, toolsCondition } from "@langchain/langgraph/prebuilt";
import { State } from "./state.js";

const getWeather = tool(
  async ({ city }) =>
    `The temperature in ${city} is 22 degrees celsius and sunny.`,
  { name: "get_weather",
    description: "Get the current weather for a city.",
    schema: z.object({ city: z.string() }) },
);

const llm = new ChatOpenAI({ model: "gpt-5-mini" }).bindTools([getWeather]);

export const builder = new StateGraph(State)
  .addNode("agent", async (s) => ({ messages: [await llm.invoke(s.messages)] }))
  .addNode("tools", new ToolNode([getWeather]))
  .addEdge(START, "agent")
  .addConditionalEdges("agent", toolsCondition) // -> tools or END
  .addEdge("tools", "agent"); // the cycle: results return to the LLM

// run.js
import { builder } from "./graph.js";

const graph = builder.compile();
const result = await graph.invoke({
  messages: [{ role: "user", content: "What's the weather in Paris?" }],
});

for (const m of result.messages) {
  console.log(m.constructor.name, "->", m.content);
}
// HumanMessage -> the question
// AIMessage    -> (empty content, tool call for get_weather)
// ToolMessage  -> 22 degrees celsius and sunny...
// AIMessage    -> final answer

