  prompt: "What's the weather in Paris?",
  options: {
    model: "claude-sonnet-4-6",
    mcpServers: { labtools: server },
    allowedTools: ["mcp__labtools__get_weather"],
  },
})) {
  if (message.type === "result" && message.subtype === "success") {
    console.log(message.result);
  }
}

// session.js
import { query } from "@anthropic-ai/claude-agent-sdk";

async function* turns() {
  yield { type: "user", message: { role: "user",
    content: "Count the JavaScript files in this directory." } };
  // same session -- the agent remembers the first turn
  yield { type: "user", message: { role: "user",
    content: "Which of those files is the largest?" } };
}

for await (const message of query({
  prompt: turns(),
  options: { model: "claude-sonnet-4-6", allowedTools: ["Read", "Glob"] },
})) {
  if (message.type === "result" && message.subtype === "success") {
    console.log(message.result);
  }
}
